function sliderReviews() {
    var swiper = new Swiper('.architecture .mySwiper', {
        slidesPerView: 1,
        spaceBetween: 15,
        speed: 500,
        allowTouchMove: false,
        pagination: {
            el: ".architecture .swiper-pagination",
            clickable: true,
        },
    })
}

function sliderFormats() {
    var swiper = new Swiper('.formats .mySwiper', {
        slidesPerView: 2,
        spaceBetween: 80,
        speed: 500,
        pagination: {
            el: ".formats .swiper-pagination",
            clickable: true,
        },
        breakpoints: {
            320: {
                slidesPerView: 1,
                spaceBetween: 30,
            },
            577: {
                slidesPerView: 1.5,
                spaceBetween: 40,
            },
            993: {
                slidesPerView: 2,
                spaceBetween: 80,
            }
        }
    })
}

$(document).ready(function () {
    sliderReviews();
    sliderFormats();

    const header = document.querySelector('.header');

    if (header) {
        function fixHeader() {
            const headerHeight = header.offsetHeight;

            const wrapper = document.querySelector('.wrapper');
            if (wrapper) {
                wrapper.style.paddingTop = headerHeight + 'px';
            }
        }

        window.addEventListener('load', fixHeader);
        window.addEventListener('resize', fixHeader);
    }


})

